    SHEET="学生表",
    HEADER=true,
    MAPPING={
        "id":"主键",
        "name":"姓名",
        "gender":"性别",
        "age":"年龄",
        "enrollmentDate":"入学时间",
        "className":"班级",
        "ignoreField":"是否忽略"
